            // Helper: find region data by name
            $resolve = function (string $name) use ($regions): array {
                foreach ($regions as $r) {
                    if (strtolower($r['name']) === strtolower($name)) return $r;
                }
                return ['name' => $name, 'slug' => Str::slug($name), 'total' => 0, 'byNature' => []];
            };
        
