            $fill = function (string $regionName, int $value) use ($regionColors): string {
                $base = $regionColors[$regionName] ?? '#94a3b8';
                if ($value === 0) {
                    // Return a very light/desaturated version when no cases
                    return $base . '33'; // 20% opacity via hex alpha
                }
                return $base;
            };
